+fn arb_fd_budget_config() -> impl Strategy<Value = FdBudgetConfig> {
+    (
+        0.5_f64..0.9,    // warn_threshold
+        0.9_f64..1.0,    // refuse_threshold
+        1_u64..100,      // fds_per_pane
+        1000_u64..200000, // min_nofile_limit
+        5_u64..120,      // audit_interval_secs
