+        prop_assert_eq!(back.min_nofile_limit, config.min_nofile_limit);
+        prop_assert_eq!(back.audit_interval_secs, config.audit_interval_secs);
+        prop_assert_eq!(back.leak_detection_count, config.leak_detection_count);
